        return 0;
    }

    int rows = grid.length;
    int cols = grid[0].length;
    boolean[][] visited = new boolean[rows][cols];
    int regionCount = 0;

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (grid[i][j] > 200 && !visited[i][j]) {
                // Found a new bright region
                regionCount++;
                // Need to mark all connected bright cells as visited
                exploreRegion(grid, visited, i, j);
            }
        }
    }
    return regionCount;
}

private void exploreRegion(int[][] grid, boolean[][] visited, int row, int col) {
    // Check if we're out of bounds or already visited
    if (row < 0 || row >= grid.length || col < 0 || col >= grid[0].length || visited[row][col]) {
        return;
    }

    // Mark current cell as visited
    visited[row][col] = true;

    // Check adjacent cells (up, down, left, right)
    exploreRegion(grid, visited, row-1, col); // Up
    exploreRegion(grid, visited, row+1, col); // Down  
    exploreRegion(grid, visited, row, col-1); // Left
    exploreRegion(grid, visited, row, col+1); // Right
}
